 1→import { useId } from 'react';
 2→import { FormField } from './form_field';
 3→
 4→interface FormTextFieldProps {
 5→  label: string;
 6→  value: string;
 7→  onChange: (value: string) => void;
 8→  placeholder?: string;
 9→  description?: string;
10→  error?: string;
11→  autoFocus?: boolean;
12→}
13→
14→export function FormTextField({
15→  label,
16→  value,
17→  onChange,
18→  placeholder,
19→  description,
20→  error,
21→  autoFocus,
22→}: FormTextFieldProps) {
23→  const id = useId();
24→
25→  return (
26→    <FormField
27→      label={label}
28→      description={description}
29→      error={error}
30→      htmlFor={id}
31→    >
32→      <input
33→        id={id}
34→        className="form-input"
35→        type="text"
36→        value={value}
37→        onChange={e => onChange(e.target.value)}
38→        placeholder={placeholder}
39→        autoFocus={autoFocus}
40→        spellCheck={false}
41→        autoComplete="off"
42→        aria-invalid={error ? true : undefined}
43→        aria-describedby={error ? `${id}-error` : undefined}
44→      />
45→    </FormField>
46→  );
47→}
