 1→import { useId } from 'react';
 2→
 3→interface FormCheckboxProps {
 4→  label: string;
 5→  checked: boolean;
 6→  onChange: (checked: boolean) => void;
 7→  description?: string;
 8→  error?: string;
 9→}
10→
11→export function FormCheckbox({
12→  label,
13→  checked,
14→  onChange,
15→  description,
16→  error,
17→}: FormCheckboxProps) {
18→  const id = useId();
19→
20→  return (
21→    <div className={`form-checkbox${error ? ' form-checkbox--error' : ''}`}>
22→      <div className="form-checkbox__row">
23→        <input
24→          id={id}
25→          type="checkbox"
26→          className="form-checkbox__input"
27→          checked={checked}
28→          onChange={e => onChange(e.target.checked)}
29→          aria-invalid={error ? true : undefined}
30→          aria-describedby={error ? `${id}-error` : undefined}
31→        />
32→        <div
33→          className={`form-checkbox__box${checked ? ' form-checkbox__box--checked' : ''}`}
34→          aria-hidden="true"
35→        >
36→          {checked && (
37→            <svg
38→              width="10"
39→              height="10"
40→              viewBox="0 0 10 10"
41→              fill="none"
42→              xmlns="http://www.w3.org/2000/svg"
43→            >
44→              <path
45→                d="M2 5L4.5 7.5L8 2.5"
46→                stroke="currentColor"
47→                strokeWidth="1.5"
48→                strokeLinecap="round"
49→                strokeLinejoin="round"
50→              />
51→            </svg>
52→          )}
53→        </div>
54→        <label className="form-checkbox__label" htmlFor={id}>
55→          {label}
56→        </label>
57→      </div>
58→      {error && (
59→        <span className="form-checkbox__error" id={`${id}-error`}>
60→          {error}
61→        </span>
62→      )}
63→      {!error && description && (
64→        <span className="form-checkbox__description">{description}</span>
65→      )}
66→    </div>
67→  );
68→}
